body.content:
super.layout()

    let numSpaces = CGFloat(tickMarkLabels.count - 1)
    for (i, constraint) in tickMarkTextFieldsConstraints.enumerated() {
      let xPos = xOffset(CGFloat(i + 1) / numSpaces)
      if constraint.constant != xPos {
        constraint.constant = xPos
      }
    }
    updateIndicator()
